SELECT COUNT(*) AS total_tokens,
       COUNT(*) FILTER (WHERE status = 'VALID')   AS valid_tokens,
       COUNT(*) FILTER (WHERE status = 'UNKNOWN') AS unknown_tokens,
       COUNT(*) FILTER (WHERE status = 'INVALID') AS invalid_tokens
FROM api.greenhouse_board_tokens;